protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Blog>(b =>
    {
        // EF 9 renamed the JSON discriminator from "Discriminator" to "$type".
        // Preserve the old name so existing documents are still found.
        b.HasDiscriminator<string>("Discriminator");

        // EF 9 no longer synthesizes the Cosmos id as "Discriminator|Key".
        // Convert to/from the legacy "Blog|{key}" format for existing documents.
        b.Property(e => e.Id)
            .HasConversion(
                v => "Blog|" + v,
                v => v.Substring(v.IndexOf('|') + 1));

        // REMOVED – EF 9 Cosmos provider throws on HasIndex (not supported).
        // Was: b.HasIndex(e => e.Name);
    });
}

